toolArgs.file_text:
@using sv_8b1412fb46084546be45a26492034e43.Services

<aside class="catalog-sidebar">
    <h3>Filters</h3>

    <div class="filter-section">
        <h4>Category</h4>
        @foreach (var category in Categories)
        {
            <label class="checkbox-label">
                <input type="checkbox"
                       checked="@_selectedCategories.Contains(category)"
                       @onchange="@(e => ToggleCategory(category, (bool)e.Value!))" />
                @category
            </label>
        }
    </div>

    <div class="filter-section">
        <h4>Price Range</h4>
        <div class="price-inputs">
            <input type="number" placeholder="Min" min="0" step="0.01"
                   value="@_minPrice"
                   @onchange="@(e => _minPrice = ParseDecimal(e.Value))" />
            <span class="price-separator">–</span>
            <input type="number" placeholder="Max" min="0" step="0.01"
                   value="@_maxPrice"
                   @onchange="@(e => _maxPrice = ParseDecimal(e.Value))" />
        </div>
    </div>

    <div class="filter-section">
        <label class="checkbox-label">
            <input type="checkbox" @bind="_inStockOnly" />
            In Stock Only
        </label>
    </div>

    <div class="filter-actions">
        <button class="btn-apply" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn-clear" @onclick="ClearFilters">Clear Filters</button>
    </div>
</aside>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public EventCallback<ProductFilter> OnFilterApplied { get; set; }

    [Parameter]
    public EventCallback OnFilterCleared { get; set; }

    private readonly HashSet<string> _selectedCategories = [];
    private decimal? _minPrice;
    private decimal? _maxPrice;
    private bool _inStockOnly;

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            _selectedCategories.Add(category);
        else
            _selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: _selectedCategories.Count > 0 ? _selectedCategories.ToList() : null,
            MinPrice: _minPrice,
            MaxPrice: _maxPrice,
            InStockOnly: _inStockOnly
        );
        await OnFilterApplied.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        _selectedCategories.Clear();
        _minPrice = null;
        _maxPrice = null;
        _inStockOnly = false;
        await OnFilterCleared.InvokeAsync();
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

.catalog-sidebar {
    background: #fafafa;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.25rem;
}

.catalog-sidebar h3 {
    margin: 0 0 1rem;
    font-size: 1.2rem;
    color: #333;
}

.filter-section {
    margin-bottom: 1.25rem;
}

.filter-section h4 {
    margin: 0 0 0.5rem;
    font-size: 0.9rem;
    color: #555;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.checkbox-label {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.25rem 0;
    cursor: pointer;
    font-size: 0.95rem;
}

.price-inputs {
    display: flex;
    align-items: center;
    gap: 0.5rem;
}

.price-inputs input {
    width: 100%;
    padding: 0.4rem 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.9rem;
}

.price-separator {
    color: #999;
}

.filter-actions {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.btn-apply {
    padding: 0.5rem 1rem;
    background: #2a7ae2;
    color: #fff;
