.catalog-pagination {
    display: flex;
    justify-content: center;
    align-items: center;
    gap: 0.4rem;
    margin-top: 2rem;
    flex-wrap: wrap;
}

.page-btn {
    padding: 0.45rem 0.85rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    background: #fff;
    cursor: pointer;
    font-size: 0.9rem;
    transition: background 0.15s, border-color 0.15s;
}

.page-btn:hover:not(:disabled):not(.active) {
    background: #f0f0f0;
    border-color: #999;
}

.page-btn.active {
    background: #2a7ae2;
    color: #fff;
    border-color: #2a7ae2;
    font-weight: 600;
}

.page-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

