arguments.file_text:
@page "/catalog"
@using sv_8b1412fb46084546be45a26492034e43.Services
@using sv_8b1412fb46084546be45a26492034e43.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (_error is not null)
{
    <div class="catalog-error">
        <p>⚠️ Something went wrong: @_error</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else
{
    <div class="catalog-layout">
        <CatalogSidebar Categories="_categories"
                        OnFilterApplied="HandleFilterApplied"
                        OnFilterCleared="HandleFilterCleared" />

        <main class="catalog-main">
            <CatalogToolbar SortBy="@_sortBy"
                            TotalCount="_totalCount"
                            Page="_currentPage"
                            PageSize="PageSize"
                            OnSortChanged="HandleSortChanged" />

            @if (_loading)
            {
                <div class="catalog-loading">
                    <p>Loading products…</p>
                </div>
            }
            else if (_products.Count == 0)
            {
                <div class="catalog-empty">
                    <p>No products match your criteria. Try adjusting your filters.</p>
                </div>
            }
            else
            {
                <ProductGrid Products="_products"
                             OnProductSelected="OnProductSelected"
                             OnAddToCart="HandleAddToCart" />

                @if (_totalPages > 1)
                {
                    <CatalogPagination CurrentPage="_currentPage"
                                       TotalPages="_totalPages"
                                       OnPageChanged="HandlePageChanged" />
                }
            }
        </main>
    </div>
}

@code {
    private const int PageSize = 12;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<Product> _products = [];
    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private int _totalCount;
    private int _totalPages;
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        try
        {
            _loading = true;
            _error = null;

            var categoriesTask = _categories.Count == 0
                ? ProductService.GetCategoriesAsync()
                : Task.FromResult(_categories);

            var searchTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, searchTask);

            _categories = await categoriesTask;
            var result = await searchTask;

            _products = result.Items;
            _totalCount = result.TotalCount;
            _totalPages = (int)Math.Ceiling((double)result.TotalCount / PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleFilterCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await LoadDataAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await LoadDataAsync();
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for add-to-cart functionality
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

.catalog-layout {
    display: flex;
    gap: 2rem;
    align-items: flex-start;
}

.catalog-layout > :first-child {
    flex: 0 0 25%;
    min-width: 220px;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.catalog-loading,
.catalog-empty,
.catalog-error {
    text-align: center;
    padding: 3rem 1rem;
    color: #666;
    font-size: 1.1rem;
}

.catalog-error {
    background: #fef2f2;
    border: 1px solid #fca5a5;
    border-radius: 8px;
    color: #991b1b;
}

.catalog-error button {
    margin-top: 1rem;
    padding: 0.5rem 1.5rem;
    background: #2a7ae2;
    color: #fff;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 600;
}

